import { useState, useEffect } from 'react';
import { api } from '../utils/api';

export default function useAIAccess() {
  let user = {};
  try { user = JSON.parse(localStorage.getItem('aura_user') || '{}'); } catch {}
  const isAdmin = user.role === 'admin';
  const [aiStatus, setAiStatus] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api('/assistant/status')
      .then((data) => {
        if (data) setAiStatus(data);
      })
      .finally(() => setLoading(false));
  }, []);

  const hasAccess = isAdmin || aiStatus?.is_admin || (aiStatus?.enabled && aiStatus?.budget?.remaining > 0);
  const tier = isAdmin || aiStatus?.is_admin ? 'enterprise' : aiStatus?.tier || null;

  return { hasAccess, isAdmin: isAdmin || aiStatus?.is_admin, aiStatus, tier, loading };
}
