import { useState, useEffect, useRef, useCallback } from 'react';
import useAIAccess from '../hooks/useAIAccess';
import { getApiBase } from '../utils/platform';
import { AI_ADDON_PRICING } from '../config/pricing';

const C = {
  bg: '#0B0F14', surface: '#0F1620', surface2: '#111A24',
  border: '#1F2A37', textPrimary: '#E5E7DB', textSecondary: '#90A3AF',
  green: '#22C55E', red: '#EF4444', blue: '#60A5FA',
  amber: '#F59E0B', purple: '#A78BFA',
};
const mono = "'JetBrains Mono', monospace";
const body = "'Plus Jakarta Sans', sans-serif";

function authHeaders() {
  try {
    const token = localStorage.getItem('aura_token');
    return token ? { Authorization: `Bearer ${token}` } : {};
  } catch { return {}; }
}

function formatTokens(n) {
  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
  if (n >= 1_000) return `${(n / 1_000).toFixed(0)}K`;
  return String(n);
}

/* ── Quick Action Buttons ──────────────────────────────────── */
function QuickActions({ onAction, disabled }) {
  const actions = [
    { key: 'analyze', label: 'Analyze Results', icon: '📊' },
    { key: 'recommend', label: 'Strategy Recs', icon: '🎯' },
    { key: 'explain', label: 'Explain Performance', icon: '💡' },
    { key: 'paper', label: 'Paper Trade Ideas', icon: '📝' },
  ];
  return (
    <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8, padding: '8px 12px' }}>
      {actions.map((a) => (
        <button
          key={a.key}
          onClick={() => onAction(a.key)}
          disabled={disabled}
          style={{
            fontFamily: body, fontSize: 11, fontWeight: 600,
            padding: '6px 10px', borderRadius: 6,
            border: `1px solid ${C.border}`, background: C.surface2,
            color: disabled ? C.textSecondary : C.textPrimary,
            cursor: disabled ? 'not-allowed' : 'pointer',
            transition: 'all 0.15s', whiteSpace: 'nowrap',
            opacity: disabled ? 0.5 : 1,
          }}
        >
          {a.icon} {a.label}
        </button>
      ))}
    </div>
  );
}

/* ── What-If Scenario Builder ─────────────────────────────── */
function WhatIfBuilder({ onSubmit, disabled }) {
  const [open, setOpen] = useState(false);
  const [scenario, setScenario] = useState('');
  const [capital, setCapital] = useState('');
  const [region, setRegion] = useState('');

  const handleSubmit = () => {
    if (!scenario.trim()) return;
    onSubmit({ scenario: scenario.trim(), capital: capital ? Number(capital) : null, region: region || null });
    setScenario('');
    setOpen(false);
  };

  if (!open) {
    return (
      <button
        onClick={() => setOpen(true)}
        disabled={disabled}
        style={{
          fontFamily: body, fontSize: 11, fontWeight: 600,
          padding: '6px 10px', borderRadius: 6,
          border: `1px solid ${C.purple}40`, background: `${C.purple}12`,
          color: disabled ? C.textSecondary : C.purple,
          cursor: disabled ? 'not-allowed' : 'pointer',
          margin: '0 12px 8px', opacity: disabled ? 0.5 : 1,
        }}
      >
        🔮 What-If Scenario
      </button>
    );
  }

  return (
    <div style={{
      margin: '0 12px 8px', padding: 12, borderRadius: 10,
      background: C.surface2, border: `1px solid ${C.purple}30`,
    }}>
      <div style={{ fontSize: 11, fontWeight: 600, color: C.purple, marginBottom: 8, fontFamily: body }}>
        What-If Scenario
      </div>
      <textarea
        value={scenario}
        onChange={(e) => setScenario(e.target.value)}
        placeholder="e.g. What if I only traded Breakout and Bullish Pullback with $50k?"
        rows={2}
        style={{
          width: '100%', boxSizing: 'border-box', resize: 'none',
          fontFamily: body, fontSize: 13, padding: 8, borderRadius: 6,
          border: `1px solid ${C.border}`, background: C.surface,
          color: C.textPrimary, outline: 'none', marginBottom: 8,
        }}
      />
      <div style={{ display: 'flex', gap: 8, marginBottom: 8 }}>
        <input
          type="number" placeholder="Capital ($)" value={capital}
          onChange={(e) => setCapital(e.target.value)}
          style={{
            flex: 1, fontFamily: mono, fontSize: 11, padding: '6px 8px',
            borderRadius: 6, border: `1px solid ${C.border}`,
            background: C.surface, color: C.textPrimary, outline: 'none',
          }}
        />
        <select
          value={region} onChange={(e) => setRegion(e.target.value)}
          style={{
            flex: 1, fontFamily: mono, fontSize: 11, padding: '6px 8px',
            borderRadius: 6, border: `1px solid ${C.border}`,
            background: C.surface, color: C.textPrimary, outline: 'none',
          }}
        >
          <option value="">Any region</option>
          <option value="us">US</option>
          <option value="europe_equities">Europe</option>
          <option value="futures_cme">Futures</option>
          <option value="forex">Forex</option>
          <option value="crypto">Crypto</option>
        </select>
      </div>
      <div style={{ display: 'flex', gap: 8 }}>
        <button
          onClick={handleSubmit}
          disabled={!scenario.trim() || disabled}
          style={{
            fontFamily: body, fontSize: 11, fontWeight: 600,
            padding: '6px 14px', borderRadius: 6, border: 'none',
            background: C.purple, color: '#fff',
            cursor: !scenario.trim() || disabled ? 'not-allowed' : 'pointer',
            opacity: !scenario.trim() || disabled ? 0.5 : 1,
          }}
        >
          Analyze
        </button>
        <button
          onClick={() => setOpen(false)}
          style={{
            fontFamily: body, fontSize: 11, padding: '6px 10px',
            borderRadius: 6, border: `1px solid ${C.border}`,
            background: 'transparent', color: C.textSecondary, cursor: 'pointer',
          }}
        >
          Cancel
        </button>
      </div>
    </div>
  );
}

/* ── Message Bubble ────────────────────────────────────────── */
function MessageBubble({ role, content }) {
  const isUser = role === 'user';
  return (
    <div style={{
      display: 'flex', justifyContent: isUser ? 'flex-end' : 'flex-start',
      marginBottom: 12, padding: '0 12px',
    }}>
      <div style={{
        maxWidth: '90%', padding: '10px 12px', borderRadius: 10,
        background: isUser ? `${C.blue}18` : C.surface,
        border: `1px solid ${isUser ? `${C.blue}30` : C.border}`,
      }}>
        <div style={{
          fontFamily: body, fontSize: 13, lineHeight: 1.6,
          color: C.textPrimary, whiteSpace: 'pre-wrap', wordBreak: 'break-word',
        }}>
          {content}
        </div>
      </div>
    </div>
  );
}

/* ── Streaming Text ────────────────────────────────────────── */
function StreamingText({ text }) {
  return (
    <div style={{
      display: 'flex', justifyContent: 'flex-start',
      marginBottom: 12, padding: '0 12px',
    }}>
      <div style={{
        maxWidth: '90%', padding: '10px 12px', borderRadius: 10,
        background: C.surface, border: `1px solid ${C.border}`,
      }}>
        <div style={{
          fontFamily: body, fontSize: 13, lineHeight: 1.6,
          color: C.textPrimary, whiteSpace: 'pre-wrap', wordBreak: 'break-word',
        }}>
          {text}
          <span style={{
            display: 'inline-block', width: 5, height: 13,
            background: C.purple, marginLeft: 4, borderRadius: 1,
            animation: 'aiPanelBlink 1s step-end infinite',
          }} />
        </div>
      </div>
    </div>
  );
}

/* ── Budget Bar ────────────────────────────────────────────── */
function BudgetBar({ budget, isAdmin }) {
  if (isAdmin) {
    return (
      <div style={{
        padding: '6px 12px', borderTop: `1px solid ${C.border}`,
        fontSize: 10, color: C.green, fontFamily: mono, fontWeight: 600,
      }}>
        Admin — Unlimited AI Access
      </div>
    );
  }
  if (!budget) return null;
  const pct = budget.pct_used || 0;
  const barColor = pct > 90 ? C.red : pct > 70 ? C.amber : C.green;
  return (
    <div style={{
      padding: '6px 12px', borderTop: `1px solid ${C.border}`,
      display: 'flex', alignItems: 'center', gap: 8,
    }}>
      <span style={{ fontSize: 10, color: C.textSecondary, fontFamily: mono, whiteSpace: 'nowrap' }}>
        {formatTokens(budget.used || 0)} / {formatTokens(budget.limit || 0)}
      </span>
      <div style={{ flex: 1, height: 3, background: C.surface2, borderRadius: 6, overflow: 'hidden' }}>
        <div style={{
          width: `${Math.min(100, pct)}%`, height: '100%',
          background: barColor, borderRadius: 6,
        }} />
      </div>
      <span style={{ fontSize: 10, color: C.textSecondary, fontFamily: mono }}>{pct.toFixed(0)}%</span>
    </div>
  );
}

/* ── Subscription CTA ──────────────────────────────────────── */
function SubscriptionCTA() {
  return (
    <div style={{
      padding: 24, textAlign: 'center',
      display: 'flex', flexDirection: 'column', alignItems: 'center',
      justifyContent: 'center', height: '100%',
    }}>
      <div style={{ fontSize: 28, marginBottom: 12, opacity: 0.3 }}>AI</div>
      <div style={{ fontSize: 14, fontWeight: 600, color: C.textPrimary, marginBottom: 8, fontFamily: body }}>
        AI Backtest Assistant
      </div>
      <div style={{ fontSize: 13, color: C.textSecondary, marginBottom: 16, lineHeight: 1.5, fontFamily: body }}>
        Get AI-powered analysis of your backtest results,
        strategy recommendations, and what-if scenarios.
      </div>
      <a
        href="/ai/subscription"
        style={{
          padding: '10px 24px', borderRadius: 6, border: 'none',
          background: C.purple, color: '#fff', fontFamily: body,
          fontSize: 13, fontWeight: 600, textDecoration: 'none',
          display: 'inline-block',
        }}
      >
        Enable AI Access
      </a>
      <div style={{ marginTop: 12, fontSize: 11, color: C.textSecondary, fontFamily: body }}>
        14-day free trial, then from ${`$${AI_ADDON_PRICING.basic.price}/mo`}
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════
   MAIN COMPONENT
   ═══════════════════════════════════════════════════════════════ */
export default function BacktestAIPanel({ backtestData }) {
  const { hasAccess, isAdmin, aiStatus } = useAIAccess();
  const [open, setOpen] = useState(false);
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [sending, setSending] = useState(false);
  const [streamText, setStreamText] = useState('');
  const [conversationId, setConversationId] = useState(null);
  const messagesEndRef = useRef(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, streamText]);

  const buildExtraContext = useCallback(() => {
    if (!backtestData) return '';
    const parts = [];
    if (backtestData.results) {
      const r = backtestData.results;
      parts.push(`Total signals: ${r.total_signals || 0}`);
      parts.push(`Total P&L: $${(r.total_pnl || 0).toLocaleString()}`);
      if (r.profit_factor) parts.push(`Profit Factor: ${r.profit_factor}`);
    }
    if (backtestData.startingCapital) {
      parts.push(`Starting capital: $${backtestData.startingCapital.toLocaleString()}`);
    }
    if (backtestData.strategies && typeof backtestData.strategies === 'object') {
      const stratNames = Object.keys(backtestData.strategies);
      if (stratNames.length > 0) {
        parts.push(`Active strategies (${stratNames.length}): ${stratNames.slice(0, 10).join(', ')}${stratNames.length > 10 ? '...' : ''}`);
      }
    }
    if (backtestData.timeframe) {
      const tf = backtestData.timeframe;
      if (tf.dateFrom && tf.dateTo) parts.push(`Timeframe: ${tf.dateFrom} to ${tf.dateTo} (${tf.totalDays} days)`);
    }
    return parts.join('\n');
  }, [backtestData]);

  const sendMessage = useCallback(async (message) => {
    if (!message.trim() || sending) return;
    setSending(true);
    setMessages((prev) => [...prev, { role: 'user', content: message }]);

    try {
      const res = await fetch(`${getApiBase()}/assistant/chat`, {
        method: 'POST',
        headers: { ...authHeaders(), 'Content-Type': 'application/json' },
        body: JSON.stringify({
          message: message + '\n\n[Backtest Context]\n' + buildExtraContext(),
          conversation_id: conversationId,
          context_type: 'backtest',
          stream: true,
        }),
      });

      if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        throw new Error(err.detail || `HTTP ${res.status}`);
      }

      const reader = res.body.getReader();
      const decoder = new TextDecoder();
      let buffer = '';
      let fullText = '';
      setStreamText('');

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split('\n');
        buffer = lines.pop() || '';

        for (const line of lines) {
          if (!line.startsWith('data: ')) continue;
          const raw = line.slice(6).trim();
          if (!raw) continue;
          try {
            const event = JSON.parse(raw);
            if (event.type === 'meta' && event.conversation_id) {
              if (!conversationId) setConversationId(event.conversation_id);
            } else if (event.type === 'text') {
              fullText += event.text;
              setStreamText(fullText);
            }
          } catch { /* skip malformed */ }
        }
      }

      setStreamText('');
      setMessages((prev) => [...prev, { role: 'assistant', content: fullText }]);
    } catch (err) {
      setStreamText('');
      setMessages((prev) => [...prev, { role: 'assistant', content: `Error: ${err.message}` }]);
    } finally {
      setSending(false);
    }
  }, [sending, conversationId, buildExtraContext]);

  const handleQuickAction = useCallback((action) => {
    const prompts = {
      analyze: 'Analyze my backtest results. What are the key takeaways? Which strategies are performing well and which should I reconsider?',
      recommend: 'Based on these backtest results, which strategies should I promote to live trading? Which should I suppress? Give specific recommendations with reasoning.',
      explain: 'Explain the performance of my top and bottom performing strategies. Why are some winning and others losing? What market conditions favor each?',
      paper: 'Based on these backtest results, suggest 3-5 paper trading ideas I should test next. Include specific entry/exit criteria and position sizing.',
    };
    sendMessage(prompts[action] || action);
  }, [sendMessage]);

  const handleWhatIf = useCallback((params) => {
    const parts = [`What-if scenario: ${params.scenario}`];
    if (params.capital) parts.push(`With starting capital: $${params.capital.toLocaleString()}`);
    if (params.region) parts.push(`Focus region: ${params.region}`);
    parts.push('Provide projected P&L, risk assessment, and actionable recommendations.');
    sendMessage(parts.join('\n'));
  }, [sendMessage]);

  const handleSend = () => {
    if (!input.trim()) return;
    sendMessage(input.trim());
    setInput('');
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <>
      <style>{`@keyframes aiPanelBlink { 0%,100%{opacity:1} 50%{opacity:0} }`}</style>

      {/* Toggle button */}
      <button
        onClick={() => setOpen(!open)}
        style={{
          position: 'fixed', top: 80, right: open ? 408 : 16, zIndex: 1001,
          width: 40, height: 40, borderRadius: '50%', border: 'none',
          background: open ? C.surface2 : `linear-gradient(135deg, ${C.purple}, ${C.blue})`,
          color: '#fff', fontFamily: mono, fontSize: 14, fontWeight: 700,
          cursor: 'pointer', boxShadow: '0 4px 16px rgba(0,0,0,0.4)',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          transition: 'right 0.25s ease',
        }}
        title="AI Backtest Assistant"
      >
        {open ? '✕' : 'AI'}
      </button>

      {/* Side panel */}
      <div style={{
        position: 'fixed', top: 0, right: 0, width: 400, height: '100vh',
        background: C.bg, borderLeft: `1px solid ${C.border}`,
        zIndex: 1000, display: 'flex', flexDirection: 'column',
        transform: open ? 'translateX(0)' : 'translateX(100%)',
        transition: 'transform 0.25s ease',
        boxShadow: open ? '-8px 0 32px rgba(0,0,0,0.3)' : 'none',
      }}>
        {/* Header */}
        <div style={{
          padding: '14px 16px', borderBottom: `1px solid ${C.border}`,
          display: 'flex', alignItems: 'center', justifyContent: 'space-between',
          flexShrink: 0,
        }}>
          <div>
            <div style={{ fontSize: 14, fontWeight: 700, color: C.textPrimary, fontFamily: body }}>
              AI Backtest Assistant
            </div>
            {aiStatus?.tier && (
              <span style={{
                fontSize: 10, fontFamily: mono, color: C.purple,
                background: `${C.purple}15`, padding: '1px 6px',
                borderRadius: 6, marginTop: 4, display: 'inline-block',
              }}>
                {isAdmin ? 'Admin' : aiStatus.tier_label || aiStatus.tier}
              </span>
            )}
          </div>
          <button
            onClick={() => { setMessages([]); setConversationId(null); }}
            style={{
              fontFamily: mono, fontSize: 10, padding: '4px 8px',
              borderRadius: 6, border: `1px solid ${C.border}`,
              background: 'transparent', color: C.textSecondary,
              cursor: 'pointer',
            }}
          >
            Clear
          </button>
        </div>

        {!hasAccess ? (
          <SubscriptionCTA />
        ) : (
          <>
            {/* Quick actions + what-if */}
            <QuickActions onAction={handleQuickAction} disabled={sending} />
            <WhatIfBuilder onSubmit={handleWhatIf} disabled={sending} />

            {/* Messages area */}
            <div style={{ flex: 1, overflowY: 'auto', paddingTop: 8, paddingBottom: 8 }}>
              {messages.length === 0 && !streamText && (
                <div style={{
                  padding: 24, textAlign: 'center', color: C.textSecondary, fontSize: 13, fontFamily: body,
                }}>
                  Use the quick actions above or type a question about your backtest results.
                </div>
              )}
              {messages.map((msg, i) => (
                <MessageBubble key={i} role={msg.role} content={msg.content} />
              ))}
              {streamText && <StreamingText text={streamText} />}
              <div ref={messagesEndRef} />
            </div>

            {/* Budget bar */}
            <BudgetBar budget={aiStatus?.budget} isAdmin={isAdmin} />

            {/* Input */}
            <div style={{
              padding: '10px 12px', borderTop: `1px solid ${C.border}`,
              display: 'flex', gap: 8, alignItems: 'flex-end', flexShrink: 0,
            }}>
              <textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder="Ask about your backtest..."
                rows={1}
                style={{
                  flex: 1, resize: 'none', padding: '8px 10px', borderRadius: 6,
                  border: `1px solid ${C.border}`, background: C.surface,
                  color: C.textPrimary, fontFamily: body, fontSize: 13,
                  outline: 'none', lineHeight: 1.4, maxHeight: 80,
                }}
                onFocus={(e) => { e.currentTarget.style.borderColor = C.purple; }}
                onBlur={(e) => { e.currentTarget.style.borderColor = C.border; }}
                onInput={(e) => {
                  e.currentTarget.style.height = 'auto';
                  e.currentTarget.style.height = Math.min(e.currentTarget.scrollHeight, 80) + 'px';
                }}
              />
              <button
                onClick={handleSend}
                disabled={sending || !input.trim()}
                style={{
                  padding: '8px 14px', borderRadius: 6, border: 'none',
                  background: sending || !input.trim() ? C.surface2 : C.purple,
                  color: sending || !input.trim() ? C.textSecondary : '#fff',
                  fontFamily: body, fontSize: 13, fontWeight: 600,
                  cursor: sending || !input.trim() ? 'not-allowed' : 'pointer',
                  flexShrink: 0,
                }}
              >
                {sending ? '...' : 'Send'}
              </button>
            </div>
          </>
        )}
      </div>
    </>
  );
}
