/**
 * ShareButton -- Share backtest results or portfolio snapshots via public links.
 *
 * Usage:
 *   <ShareButton strategyKey="breakout" region="us" />
 *   <ShareButton strategyKey="breakout" region="us" includeTrades />
 *
 * Calls POST /share/backtest, copies the URL, shows confirmation.
 */
import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { api } from '../utils/api';
import T from '../tokens';

const mono = "'JetBrains Mono', monospace";
const body = "'Plus Jakarta Sans', sans-serif";

export default function ShareButton({
  strategyKey,
  region = 'us',
  timeframe = 'all',
  includeTrades = true,
  size = 'md',
  style: extraStyle = {},
}) {
  const [loading, setLoading] = useState(false);
  const [copied, setCopied] = useState(false);
  const [error, setError] = useState(null);
  const [shareUrl, setShareUrl] = useState(null);

  const handleShare = async (e) => {
    e.stopPropagation();
    if (loading) return;
    setLoading(true);
    setError(null);
    setCopied(false);

    try {
      const res = await api('/share/backtest', {
        method: 'POST',
        body: JSON.stringify({
          strategy_key: strategyKey,
          region,
          timeframe,
          include_trades: includeTrades,
        }),
      });

      if (res?.ok && res.share_url) {
        const fullUrl = `${window.location.origin}${res.share_url}`;
        setShareUrl(fullUrl);

        // Copy to clipboard
        try {
          await navigator.clipboard.writeText(fullUrl);
          setCopied(true);
          setTimeout(() => setCopied(false), 3000);
        } catch {
          // Fallback: select + copy
          const ta = document.createElement('textarea');
          ta.value = fullUrl;
          document.body.appendChild(ta);
          ta.select();
          document.execCommand('copy');
          document.body.removeChild(ta);
          setCopied(true);
          setTimeout(() => setCopied(false), 3000);
        }
      } else {
        setError(res?.detail || 'Failed to create share link');
      }
    } catch (err) {
      setError(err.message || 'Network error');
    } finally {
      setLoading(false);
    }
  };

  const isSmall = size === 'sm';

  return (
    <div style={{ position: 'relative', display: 'inline-flex', ...extraStyle }}>
      <motion.button
        onClick={handleShare}
        disabled={loading}
        whileTap={{ scale: 0.95 }}
        whileHover={{ background: 'rgba(96,165,250,0.15)' }}
        title="Share backtest results"
        style={{
          display: 'inline-flex',
          alignItems: 'center',
          gap: isSmall ? 4 : 6,
          padding: isSmall ? '4px 8px' : '6px 12px',
          borderRadius: 10,
          border: `1px solid ${T.border}`,
          background: copied ? 'rgba(34,197,94,0.1)' : 'transparent',
          color: copied ? T.green : T.blue,
          fontSize: isSmall ? 11 : 13,
          fontWeight: 600,
          fontFamily: body,
          cursor: loading ? 'wait' : 'pointer',
          opacity: loading ? 0.6 : 1,
          transition: 'all 0.25s',
        }}
      >
        {/* Share icon (inline SVG) */}
        <svg width={isSmall ? 12 : 14} height={isSmall ? 12 : 14} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2.2} strokeLinecap="round" strokeLinejoin="round">
          <circle cx="18" cy="5" r="3" />
          <circle cx="6" cy="12" r="3" />
          <circle cx="18" cy="19" r="3" />
          <line x1="8.59" y1="13.51" x2="15.42" y2="17.49" />
          <line x1="15.41" y1="6.51" x2="8.59" y2="10.49" />
        </svg>
        {loading ? 'Sharing...' : copied ? 'Copied!' : 'Share'}
      </motion.button>

      {/* Error tooltip */}
      <AnimatePresence>
        {error && (
          <motion.div
            initial={{ opacity: 0, y: -4 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0 }}
            style={{
              position: 'absolute',
              top: '100%',
              left: 0,
              marginTop: 8,
              padding: '6px 10px',
              borderRadius: 6,
              background: T.surface2,
              border: `1px solid ${T.red}`,
              color: T.red,
              fontSize: 11,
              fontFamily: body,
              whiteSpace: 'nowrap',
              zIndex: 100,
            }}
          >
            {error}
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}


/**
 * SharePortfolioButton -- Share entire portfolio snapshot.
 */
export function SharePortfolioButton({
  strategies = [],
  performanceSummary = {},
  title = 'My Portfolio',
  style: extraStyle = {},
}) {
  const [loading, setLoading] = useState(false);
  const [copied, setCopied] = useState(false);

  const handleShare = async (e) => {
    e.stopPropagation();
    if (loading) return;
    setLoading(true);

    try {
      const res = await api('/share/portfolio', {
        method: 'POST',
        body: JSON.stringify({
          strategies,
          performance_summary: performanceSummary,
          title,
        }),
      });

      if (res?.ok && res.share_url) {
        const fullUrl = `${window.location.origin}${res.share_url}`;
        try {
          await navigator.clipboard.writeText(fullUrl);
        } catch {
          const ta = document.createElement('textarea');
          ta.value = fullUrl;
          document.body.appendChild(ta);
          ta.select();
          document.execCommand('copy');
          document.body.removeChild(ta);
        }
        setCopied(true);
        setTimeout(() => setCopied(false), 3000);
      }
    } catch {
      // silent fail
    } finally {
      setLoading(false);
    }
  };

  return (
    <motion.button
      onClick={handleShare}
      disabled={loading}
      whileTap={{ scale: 0.95 }}
      whileHover={{ background: 'rgba(96,165,250,0.15)' }}
      style={{
        display: 'inline-flex',
        alignItems: 'center',
        gap: 8,
        padding: '6px 12px',
        borderRadius: 10,
        border: `1px solid ${T.border}`,
        background: copied ? 'rgba(34,197,94,0.1)' : 'transparent',
        color: copied ? T.green : T.blue,
        fontSize: 13,
        fontWeight: 600,
        fontFamily: "'Plus Jakarta Sans', sans-serif",
        cursor: loading ? 'wait' : 'pointer',
        ...extraStyle,
      }}
    >
      <svg width={14} height={14} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2.2} strokeLinecap="round" strokeLinejoin="round">
        <circle cx="18" cy="5" r="3" />
        <circle cx="6" cy="12" r="3" />
        <circle cx="18" cy="19" r="3" />
        <line x1="8.59" y1="13.51" x2="15.42" y2="17.49" />
        <line x1="15.41" y1="6.51" x2="8.59" y2="10.49" />
      </svg>
      {loading ? 'Sharing...' : copied ? 'Link Copied!' : 'Share Portfolio'}
    </motion.button>
  );
}
