/* ═══════════════════════════════════════════════════════════════
   HELPERS -- formatting, math
   ═══════════════════════════════════════════════════════════════ */
function fmtDollar(v) {
  if (v == null || !isFinite(v)) return '\u2014';
  if (Math.abs(v) >= 1e6) return `$${(v / 1e6).toFixed(1)}M`;
  if (Math.abs(v) >= 1e3) return `$${(v / 1e3).toFixed(1)}K`;
  return `$${Math.round(v).toLocaleString()}`;
}

function fmtDollarSigned(v) {
  if (v == null) return '\u2014';
  const abs = Math.abs(v);
  const sv = abs >= 1e6 ? `$${(abs / 1e6).toFixed(1)}M` : abs >= 1000 ? `$${(abs / 1000).toFixed(1)}k` : `$${abs.toFixed(0)}`;
  return v >= 0 ? `+${sv}` : `\u2212${sv}`;
}

function fmtPct(v, d = 1) { return v != null && !isNaN(v) && isFinite(v) ? `${v >= 0 ? '+' : ''}${v.toFixed(d)}%` : '\u2014'; }

function computeCAGR(startVal, endVal, days) {
  if (!startVal || startVal <= 0 || !days || days <= 0) return 0;
  if (endVal <= 0) return -100;
  const years = days / 365.25;
  if (years <= 0) return 0;
  return (Math.pow(endVal / startVal, 1 / years) - 1) * 100;
}

function durationLabel(days) {
  const years = Math.floor(days / 365);
  const months = Math.floor((days % 365) / 30);
  const d = days % 30;
  const parts = [];
  if (years > 0) parts.push(`${years}y`);
  if (months > 0) parts.push(`${months}m`);
  if (d > 0 || parts.length === 0) parts.push(`${d}d`);
  return parts.join(' ');
}

function formatFullDate(dateStr) {
  if (!dateStr) return '\u2014';
  const d = new Date(dateStr);
  return d.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
}

function pfColor(pf) {
  if (pf == null) return C.textSecondary;
  if (pf >= 50) return C.green;   // sentinel: no losses
  if (pf >= 3) return C.green;
  if (pf >= 2) return C.amber;
  return C.red;
}
function fmtPF(pf) {
  if (pf == null) return '--';
  if (pf >= 50) return '\u221E';
  return pf.toFixed(2);
}

