/* ═══════════════════════════════════════════════════════════════
   SVG CHARTS -- Equity Curve, Daily P&L, Return Histogram
   ═══════════════════════════════════════════════════════════════ */
function EquityCurveSVG({ data, benchmark }) {
  if (!data || data.length === 0) return null;
  const labelW = 65, w = 800, h = 200, padY = 10;

  // Normalize both series to starting value = 100 for fair comparison
  const norm = data[0] !== 0 ? data.map(v => (v / data[0]) * 100) : data;
  const normBench = benchmark && benchmark.length > 1 && benchmark[0] !== 0
    ? benchmark.map(v => (v / benchmark[0]) * 100)
    : null;

  // Find min/max across both series
  const allVals = normBench ? [...norm, ...normBench] : norm;
  const min = Math.min(...allVals), max = Math.max(...allVals);
  const range = max - min || 1;
  const last = norm[norm.length - 1];
  const lastColor = last >= norm[0] ? C.green : C.red;

  const toPoint = (arr) => arr.map((v, i) => {
    const x = labelW + (i / (arr.length - 1)) * (w - labelW);
    const y = padY + (1 - (v - min) / range) * (h - padY * 2);
    return `${x},${y}`;
  }).join(' ');

  const points = toPoint(norm);
  const benchPoints = normBench ? toPoint(normBench) : null;

  const yForVal = (v) => padY + (1 - (v - min) / range) * (h - padY * 2);
  return (
    <svg viewBox={`0 0 ${w} ${h}`} style={{ width: '100%', height: 200 }}>
      <defs>
        <linearGradient id="eqGrad" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor={lastColor} stopOpacity="0.2" />
          <stop offset="100%" stopColor={lastColor} stopOpacity="0" />
        </linearGradient>
      </defs>
      <text x={labelW - 6} y={yForVal(max) + 4} textAnchor="end" fill={C.textSecondary} fontSize="9" fontFamily={mono}>{fmtPct(max - 100)}</text>
      <text x={labelW - 6} y={yForVal(min) + 4} textAnchor="end" fill={C.textSecondary} fontSize="9" fontFamily={mono}>{fmtPct(min - 100)}</text>
      <text x={labelW - 6} y={yForVal(last) + 4} textAnchor="end" fill={lastColor} fontSize="9" fontWeight="700" fontFamily={mono}>{fmtPct(last - 100)}</text>
      <line x1={labelW} y1={yForVal(max)} x2={w} y2={yForVal(max)} stroke={C.border} strokeWidth="0.5" strokeDasharray="3,3" />
      <line x1={labelW} y1={yForVal(min)} x2={w} y2={yForVal(min)} stroke={C.border} strokeWidth="0.5" strokeDasharray="3,3" />
      <line x1={labelW} y1={yForVal(last)} x2={w} y2={yForVal(last)} stroke={lastColor} strokeWidth="0.5" strokeDasharray="4,3" opacity="0.5" />
      {/* SPY benchmark line (if available) */}
      {benchPoints && (
        <polyline points={benchPoints} fill="none" stroke={C.amber} strokeWidth="1.5" strokeDasharray="4,3" opacity="0.7" />
      )}
      <polygon points={`${labelW},${h - padY} ${points} ${w},${h - padY}`} fill="url(#eqGrad)" />
      <polyline points={points} fill="none" stroke={lastColor} strokeWidth="2" strokeLinejoin="round" />
      {/* Legend */}
      {benchPoints && (
        <g>
          <line x1={w - 140} y1={12} x2={w - 120} y2={12} stroke={lastColor} strokeWidth="2" />
          <text x={w - 116} y={15} fill={C.textPrimary} fontSize="8" fontFamily={mono}>Strategy</text>
          <line x1={w - 70} y1={12} x2={w - 50} y2={12} stroke={C.amber} strokeWidth="1.5" strokeDasharray="4,3" />
          <text x={w - 46} y={15} fill={C.amber} fontSize="8" fontFamily={mono}>SPY</text>
        </g>
      )}
    </svg>
  );
}

function DailyPnLSVG({ data }) {
  const labelW = 65, w = 800, h = 160, padY = 10;
  const maxAbs = Math.max(...data.map(Math.abs), 1);
  const mid = h / 2, chartW = w - labelW;
  const barW = Math.max(1, (chartW / data.length) * 0.7);
  const gap = chartW / data.length;
  return (
    <svg viewBox={`0 0 ${w} ${h}`} style={{ width: '100%', height: 160 }}>
      <text x={labelW - 6} y={padY + 4} textAnchor="end" fill={C.green} fontSize="9" fontFamily={mono}>+{fmtDollar(maxAbs)}</text>
      <text x={labelW - 6} y={mid + 4} textAnchor="end" fill={C.textSecondary} fontSize="9" fontFamily={mono}>$0</text>
      <text x={labelW - 6} y={h - padY + 4} textAnchor="end" fill={C.red} fontSize="9" fontFamily={mono}>-{fmtDollar(maxAbs)}</text>
      <line x1={labelW} y1={mid} x2={w} y2={mid} stroke={C.border} strokeWidth="1" />
      <line x1={labelW} y1={padY} x2={w} y2={padY} stroke={C.border} strokeWidth="0.5" strokeDasharray="3,3" />
      <line x1={labelW} y1={h - padY} x2={w} y2={h - padY} stroke={C.border} strokeWidth="0.5" strokeDasharray="3,3" />
      {data.map((v, i) => {
        const barH = (Math.abs(v) / maxAbs) * (mid - padY);
        const x = labelW + i * gap + (gap - barW) / 2;
        const y = v >= 0 ? mid - barH : mid;
        return <rect key={i} x={x} y={y} width={barW} height={barH} fill={v >= 0 ? C.green : C.red} opacity={0.85} rx={1} />;
      })}
    </svg>
  );
}

